import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/quick-start.md","filePath":"getting-started/quick-start.md","lastUpdated":null}'),n={name:"getting-started/quick-start.md"};function o(r,e,p,d,l,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This tutorial walks you through creating your first A/B experiment from scratch. By the end you will have a running Vite + Preact project with a clipboard-ready IIFE bundle ready to paste into Adobe Target.</p><p><strong>Time to complete:</strong> ~10 minutes</p><p><strong>Prerequisites:</strong> Node 24 and pnpm 10.30.1 installed. If not, complete <a href="/getting-started/prerequisites.html">Prerequisites</a> first.</p><hr><h2 id="step-1-scaffold-the-project" tabindex="-1">Step 1: Scaffold the project <a class="header-anchor" href="#step-1-scaffold-the-project" aria-label="Permalink to &quot;Step 1: Scaffold the project&quot;">​</a></h2><p>Run the create command and follow the prompts:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @sogody/experiment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-first-experiment</span></span></code></pre></div><p>When prompted, answer:</p><table tabindex="0"><thead><tr><th>Prompt</th><th>Recommended answer</th></tr></thead><tbody><tr><td>Select boilerplate</td><td><code>product-card</code></td></tr><tr><td>Number of variations</td><td><code>2</code> (creates v1 and v2)</td></tr><tr><td>Window namespace</td><td><code>sgd</code> (default)</td></tr><tr><td>Include emergency brake</td><td><code>Yes</code> (default)</td></tr><tr><td>Enable E2E testing</td><td><code>No</code> (default — add later if needed)</td></tr></tbody></table><p>The CLI generates the project, installs dependencies, and prints next steps.</p><h2 id="step-2-switch-to-the-correct-node-version" tabindex="-1">Step 2: Switch to the correct Node version <a class="header-anchor" href="#step-2-switch-to-the-correct-node-version" aria-label="Permalink to &quot;Step 2: Switch to the correct Node version&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-first-experiment</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> use</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # reads .nvmrc — switches to Node 24</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Always run nvm use first</p><p>The <code>package.json</code> <code>packageManager</code> field locks pnpm to <code>10.30.1</code>. Running <code>pnpm</code> commands on a different Node version can cause lockfile errors.</p></div><h2 id="step-3-start-watch-mode-for-variation-1" tabindex="-1">Step 3: Start watch mode for variation 1 <a class="header-anchor" href="#step-3-start-watch-mode-for-variation-1" aria-label="Permalink to &quot;Step 3: Start watch mode for variation 1&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><p>You will see Vite build output followed by:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ built in 312ms</span></span>
<span class="line"><span>📋 v1 bundle copied to clipboard</span></span></code></pre></div><p>Every time you save a source file, Vite rebuilds and copies the latest bundle to your clipboard automatically.</p><h2 id="step-4-paste-into-adobe-target" tabindex="-1">Step 4: Paste into Adobe Target <a class="header-anchor" href="#step-4-paste-into-adobe-target" aria-label="Permalink to &quot;Step 4: Paste into Adobe Target&quot;">​</a></h2><ol><li>Open your Adobe Target activity.</li><li>Navigate to the <strong>Custom Code</strong> editor for the variation you are developing.</li><li>Select all existing content in the editor and paste (<code>Cmd+V</code> / <code>Ctrl+V</code>).</li><li>Click <strong>Save</strong> and refresh your preview page.</li></ol><p>The experiment renders on the page. No manual bundle copying needed — the clipboard is always up to date on save.</p><h2 id="step-5-edit-the-experiment" tabindex="-1">Step 5: Edit the experiment <a class="header-anchor" href="#step-5-edit-the-experiment" aria-label="Permalink to &quot;Step 5: Edit the experiment&quot;">​</a></h2><p>Open <code>src/config.js</code> and set the selector for your target page:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> testName</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;my-first-experiment&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> targetSelector</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.your-page-selector&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ← update this</span></span></code></pre></div><p>Save the file. Vite rebuilds instantly and copies the new bundle to your clipboard. Paste into Adobe Target and refresh.</p><h2 id="step-6-run-a-production-build" tabindex="-1">Step 6: Run a production build <a class="header-anchor" href="#step-6-run-a-production-build" aria-label="Permalink to &quot;Step 6: Run a production build&quot;">​</a></h2><p>When your experiment is ready:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dist/</span></span>
<span class="line"><span>├── v1/</span></span>
<span class="line"><span>│   └── v1.js</span></span>
<span class="line"><span>└── v2/</span></span>
<span class="line"><span>    └── v2.js</span></span></code></pre></div><p>Each file is a self-contained IIFE bundle. Upload or paste these into Adobe Target for your production activity.</p><hr><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><a href="/getting-started/project-structure.html">Project Structure</a> — understand every generated file</li><li><a href="/development/variations.html">Variations</a> — add a third variation or rename existing ones</li><li><a href="/framework-api/">Framework API</a> — <code>runScript</code>, <code>waitFor</code>, <code>watchFor</code>, and tracking helpers</li><li><a href="/development/config.html">Configuration</a> — <code>experiment.config.js</code> and <code>src/config.js</code> field reference</li></ul>`,35)])])}const k=t(n,[["render",o]]);export{u as __pageData,k as default};
